function makeId(prefix) {
  return prefix + '-' + Date.now() + '-' + Math.random().toString(36).slice(2, 10)
}

function monthYear(mon, yr) {
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec']
  return { month: months[mon - 1], year: String(yr), rating: 'OK' }
}

function monthsBack(count) {
  const d = new Date()
  const result = []
  for (let i = count - 1; i >= 0; i--) {
    const m = new Date(d.getFullYear(), d.getMonth() - i, 1)
    result.push(monthYear(m.getMonth() + 1, m.getFullYear()))
  }
  return result
}

function withLate(history, lateIdx, rating) {
  return history.map((h, i) => i === lateIdx ? { ...h, rating } : h)
}

