function computeSummary(accounts, inquiries, publicRecords) {
  const openAccounts = accounts.filter(a => a.isOpen && !a.isClosed).length
  const closedAccounts = accounts.filter(a => a.isClosed).length
  const derogatoryAccounts = accounts.filter(a => a.isDerogatory).length
  const chargeOffs = accounts.filter(a => a.isChargeOff).length
  const collections = accounts.filter(a => a.isCollection).length
  const lateAccounts = accounts.filter(a => a.isLate).length
  const hardInquiries = inquiries.filter(i => i.type === 'Hard').length
  const softInquiries = inquiries.filter(i => i.type === 'Soft').length
  const totalBalance = accounts.reduce((s, a) => s + a.balance, 0)
  const totalCreditLimit = accounts.reduce((s, a) => s + (a.creditLimit || 0), 0)
  const creditUtilization = totalCreditLimit > 0 ? (totalBalance / totalCreditLimit) * 100 : 0

  return {
    totalAccounts: accounts.length,
    openAccounts,
    closedAccounts,
    derogatoryAccounts,
    chargeOffs,
    collections,
    lateAccounts,
    hardInquiries,
    softInquiries,
    publicRecords: publicRecords.length,
    bankruptcies: 0,
    totalBalance,
    totalCreditLimit,
    creditUtilization,
  }
}

experianReport.summary = computeSummary(experianReport.accounts, experianReport.inquiries, [])

