// ── SEED THE DATABASE ─────────────────────────────────────────
const db = new Database(DB_PATH)
db.pragma('journal_mode = WAL')

const upsert = db.prepare(`
  INSERT INTO reports (user_id, bureau, data, updated_at)
  VALUES (?, ?, ?, datetime('now'))
  ON CONFLICT(user_id, bureau) DO UPDATE SET data = excluded.data, updated_at = datetime('now')
`)

const upsertFico = db.prepare(`
  INSERT INTO fico_scores (user_id, bureau, score, date_updated)
  VALUES (?, ?, ?, datetime('now'))
  ON CONFLICT(user_id, bureau) DO UPDATE SET score = excluded.score, date_updated = datetime('now')
`)

const transaction = db.transaction(() => {
  for (const report of [experianReport, equifaxReport, transunionReport]) {
    const json = JSON.stringify(report)
    upsert.run(1, report.bureau, json)
    console.log(`  ✓ ${report.bureau}: ${report.accounts.length} accounts, ${report.inquiries.length} inquiries`)
  }
  upsertFico.run(1, 'Experian', 627)
  upsertFico.run(1, 'Equifax', 599)
  upsertFico.run(1, 'TransUnion', null)
})

transaction()
console.log('\nDone! Database updated successfully.')
